import{_ as a,o as i,c as n,ag as t}from"./chunks/framework.HcBc_Mb9.js";const h=JSON.parse('{"title":"AI Fluency Course Overview","description":"","frontmatter":{},"headers":[],"relativePath":"ai-fluency/index.md","filePath":"ai-fluency/index.md"}'),o={name:"ai-fluency/index.md"};function l(r,e,s,c,d,f){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="ai-fluency-course-overview" tabindex="-1">AI Fluency Course Overview <a class="header-anchor" href="#ai-fluency-course-overview" aria-label="Permalink to &quot;AI Fluency Course Overview&quot;">​</a></h1><p>The focus of this course is not really about AI as a technology<br><span style="color:#E24B4A;">How we interact and collaborate with AI systems</span></p><p>Key Takeaways<br> This course focuses on human-AI collaboration, not just understanding AI as a technology<br> AI Fluency means engaging with AI systems effectively, efficiently, ethically, and safely<br> The AI Fluency Framework centers on the &quot;4D&quot; competencies of <br> Delegation, Description, Discernment and Diligence<br> The goal is to develop lasting skills that remain relevant as AI technology evolves<br> Effective AI collaboration requires both practical skills and a fundamental shift in how we think about working with AI</p><p>Course Learning Outcomes</p><ul><li>A framework for thinking about AI Interaction</li><li>The ability to make informed decisions about when and how to engage with AI systems</li><li>Practical skills for more fluent human-AI collaboration</li><li>Confidence in evaluating and taking responsibility for AI outputs</li></ul><p>Effective/Efficient/Ethical/Safe</p><p>Course Roadmap:</p><ul><li><a href="/anthropic-notes/ai-fluency/01-ai-fluency-framework.html">AI Fluency Framework</a></li><li><a href="/anthropic-notes/ai-fluency/02-delegation.html">Delegation</a></li><li><a href="/anthropic-notes/ai-fluency/03-description.html">Description</a></li><li><a href="/anthropic-notes/ai-fluency/04-discernment.html">Discernment</a></li><li><a href="/anthropic-notes/ai-fluency/05-diligence.html">Diligence</a></li></ul><h2 id="downloads" tabindex="-1">Downloads <a class="header-anchor" href="#downloads" aria-label="Permalink to &quot;Downloads&quot;">​</a></h2><div style="border-radius:18px;background:#d2cfe3;padding:28px;display:flex;gap:24px;align-items:center;"><div style="flex:0 0 140px;text-align:center;"><div style="width:120px;height:120px;margin:0 auto;border-radius:18px;background:#f5f3f7;display:flex;align-items:center;justify-content:center;"><span style="font-size:64px;line-height:1;color:#2d2a32;">✍️</span></div></div><div style="flex:1;"><h3 style="margin:0 0 10px 0;font-size:28px;color:#2d2a32;">AI Fluency vocabulary guide</h3><p style="margin:0 0 18px 0;font-size:18px;color:#2d2a32;line-height:1.6;"> No need to memorize; just refer to it when needed. </p><a href="/anthropic-notes/ai-fluency/AI_Fluency_vocabulary_cheat_sheet.pdf" style="display:inline-block;padding:12px 22px;border-radius:12px;background:#6f6a80;color:#ffffff;text-decoration:none;font-weight:600;">Download</a></div></div>',10)])])}const p=a(o,[["render",l]]);export{h as __pageData,p as default};
